2036 |     /**
2037 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
2038 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
2039 |      */
2040 |     function smartJSONParse(jsonString) {
2041 |         try {
2042 |             return JSON.parse(jsonString);
2043 |         } catch (e) {
2044 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2045 |             let fixed = jsonString
2046 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2047 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2048 |                 // 2. Fix literal newlines inside strings (replace with \n)
2049 |                 .replace(/(\n)/g, (match, p1, offset) => {
2050 |                     // Only replace if we are likely inside a quoted string
2051 |                     const before = jsonString.slice(0, offset);
2052 |                     const quoteCount = (before.match(/"/g) || []).length;
2053 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2054 |                 });
2055 | 
2056 |             try {
2057 |                 const cleanObj = JSON.parse(fixed);
2058 |                 document.getElementById('json-input').value = fixed;
2059 |                 if (typeof saveState === 'function') saveState();
2060 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
2061 |                 return cleanObj;
2062 |             } catch (e2) {
2063 |                 console.error("Robust fix failed:", e2);
2064 |                 throw e; // Throw original error for better debugging
2065 |             }
2066 |         }
2067 |     }
