2300 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2301 |     function applyLocalPatch(content, ops) {
2302 |         let lines = content.split('\n');
2303 |         let logs = [];
2304 |         let success = true;
2305 | 
2306 |         if (typeof ops === 'string') {
2307 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2308 |         }
2309 | 
2310 |         ops.forEach(op => {
2311 |             if (op.action === 'comment') return;
2312 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2313 |             
2314 |             if (op.action === 'replace_block') {
2315 |                 // Strategy 1: Exact String Match (Fastest)
2316 |                 const currentStr = lines.join('\n');
2317 |                 if (currentStr.includes(op.find_block)) {
2318 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2319 |                     logs.push('Exact match applied');
2320 |                     return;
2321 |                 }
2322 | 
2323 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2324 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2325 |                 if (searchLines.length === 0) return;
2326 | 
2327 |                 let matchStart = -1;
2328 |                 let matchEnd = -1;
2329 | 
2330 |                 // Scan file lines
2331 |                 for (let i = 0; i < lines.length; i++) {
2332 |                     // If first line matches (ignoring whitespace)
2333 |                     if (lines[i].trim() === searchLines[0]) {
2334 |                         // Check subsequent lines
2335 |                         let allMatch = true;
2336 |                         let fileOffset = 0;
2337 |                         let searchOffset = 1;
2338 |                         
2339 |                         while (searchOffset < searchLines.length) {
2340 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2341 |                             const nextFile = lines[i + fileOffset + 1].trim();
2342 |                             // Skip empty lines in file if they aren't in search block
2343 |                             if (nextFile === '') {
2344 |                                 fileOffset++;
2345 |                                 continue;
2346 |                             }
2347 |                             if (nextFile !== searchLines[searchOffset]) {
2348 |                                 allMatch = false;
2349 |                                 break;
2350 |                             }
2351 |                             fileOffset++;
2352 |                             searchOffset++;
2353 |                         }
2354 | 
2355 |                         if (allMatch) {
2356 |                             matchStart = i;
2357 |                             matchEnd = i + fileOffset;
2358 |                             break;
2359 |                         }
2360 |                     }
2361 |                 }
2362 | 
2363 |                 if (matchStart !== -1) {
2364 |                     // Replace the range of lines
2365 |                     const replacement = op.replace_with.split('\n');
2366 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2367 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2368 |                 } else {
2369 |                     success = false;
2370 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2371 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2372 |                 }
2373 |             }
2374 |         });
2375 |         return { content: lines.join('\n'), success, logs };
2376 |     }
