2380 |     async function runAutoFixLoop(name, code, errorList) {
2381 |         const status = document.getElementById('ef-status-msg');
2382 |         let currentCode = code;
2383 |         let currentErrors = errorList;
2384 | 
2385 |         // Fix one by one (recursive loop)
2386 |         async function fixNext(index) {
2387 |             if (index >= currentErrors.length) return true; // All initial errors processed
2388 | 
2389 |             const err = currentErrors[index];
2390 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2391 |             status.style.color = "#eab308"; // Dev yellow
2392 | 
2393 |             try {
2394 |                 // 1. Get Patch from AI
2395 |                 const res = await fetch(CONFIG.funcUrl, { 
2396 |                     method: 'POST', 
2397 |                     headers: {'Content-Type': 'application/json'},
2398 |                     body: apiBody({ 
2399 |                         action: 'propose_syntax_fix', 
2400 |                         code: currentCode, 
2401 |                         error: err 
2402 |                     })
2403 |                 });
2404 |                 const data = await res.json();
2405 |                 const ops = data.operations;
2406 | 
2407 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2408 | 
2409 |                 // 2. Apply Patch Locally
2410 |                 const patchResult = applyLocalPatch(currentCode, ops);
2411 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2412 | 
2413 |                 currentCode = patchResult.content;
2414 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2415 | 
2416 |                 // 3. Re-Validate
2417 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2418 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2419 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2420 |                 });
2421 |                 const scanData = await scanRes.json();
2422 | 
2423 |                 if (scanData.valid) {
2424 |                     status.innerText = "✅ Syntax Fixed!";
2425 |                     return true;
2426 |                 } else {
2427 |                     // If errors remain, update list and Prompt user
2428 |                     currentErrors = scanData.errors;
2429 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2430 |                         // Recursively fix the *new* first error (since layout changed)
2431 |                         return await fixNext(0);
2432 |                     } else {
2433 |                         return false;
2434 |                     }
2435 |                 }
2436 | 
2437 |             } catch (e) {
2438 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2439 |                     return await fixNext(index);
2440 |                 } else {
2441 |                     return false;
2442 |                 }
2443 |             }
2444 |         }
2445 | 
2446 |         return await fixNext(0);
2447 |     }
