4177 |     async function executeRename() {
4178 |         const newPath = document.getElementById('rn-new-path').value.trim();
4179 |         const moveFolder = document.getElementById('rn-move-folder').checked;
4180 |         
4181 |         if (!newPath || newPath === currentRenamePath) return closeRenameModal();
4182 |         if (isPerformingAction) return;
4183 |         isPerformingAction = true;
4184 | 
4185 |         const getDir = (p) => p.substring(0, p.lastIndexOf('/') + 1);
4186 |         const oldDir = getDir(currentRenamePath);
4187 |         const newDir = getDir(newPath);
4188 | 
4189 |         showGlobalToast(moveFolder ? "Analyzing folder structure..." : "Preparing move...");
4190 | 
4191 |         try {
4192 |             let ops = [{ "action": "comment", "text": moveFolder ? `[Bulk Move] ${oldDir} -> ${newDir}` : `[Rename] ${currentRenamePath} -> ${newPath}` }];
4193 |             let filesToProcess = [];
4194 | 
4195 |             if (moveFolder && oldDir) {
4196 |                 // Find all siblings
4197 |                 filesToProcess = window.repoFiles.filter(f => f.path.startsWith(oldDir)).map(f => f.path);
4198 |             } else {
4199 |                 filesToProcess = [currentRenamePath];
4200 |             }
4201 | 
4202 |             // Concurrent Content Fetching
