4207 |                     const res = await fetch(CONFIG.funcUrl, {
4208 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
4209 |                         body: apiBody({ action: 'preview_file', file_path: path })
4210 |                     });
4211 |                     const data = await res.json();
4212 |                     return { path, content: b64DecodeUnicode(data.content || "") };
4213 |                 }));
4214 | 
4215 |                 batchResults.forEach(res => {
4216 |                     const targetPath = moveFolder ? res.path.replace(oldDir, newDir) : newPath;
4217 |                     ops.push({ "action": "delete_file", "file_path": res.path });
4218 |                     ops.push({ "action": "create_file", "file_path": targetPath, "content": res.content });
4219 |                 });
4220 |             }
4221 | 
4222 |             closeRenameModal();
4223 | 
4224 |             // 2. Load into Patcher
4225 |             document.getElementById('json-input').value = JSON.stringify(ops, null, 2);
4226 |             saveState();
4227 |             
4228 |             // 3. Switch to Patcher
4229 |             switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);
4230 |             
4231 |             showGlobalToast("Rename loaded. Review and Test Patch.");
4232 | 
4233 |             // 4. Prompt for AI Healing
4234 |             setTimeout(() => {
4235 |                 if (confirm("File moved! Shall I ask AI to scan and heal imports in other files?")) {
4236 |                     startNewChat();
4237 |                     toggleChat(true);
4238 |                     chatHistory.push({ 
4239 |                         role: 'user', 
4240 |                         text: `I just renamed "${currentRenamePath}" to "${newPath}". Please scan my project and provide a JSON patch to update any other files that import this file.` 
4241 |                     });
4242 |                     processAIResponse();
4243 |                 }
4244 |             }, 1000);
4245 | 
4246 |         } catch (e) {
4247 |             alert("Move failed: " + e.message);
4248 |         } finally {
