4698 |                 body: apiBody({ action: 'fetch_workflow_jobs', run_id: runId }) 
4699 |             });
4700 |             const dataJobs = await resJobs.json();
4701 |             
4702 |             // Look for a job that likely uploaded artifacts (usually named 'build' or is the successful one)
4703 |             const buildJob = dataJobs.jobs.find(j => j.name.toLowerCase().includes('build') || j.conclusion === 'success');
4704 |             
4705 |             if (!buildJob) {
4706 |                 toast.remove();
