4714 |                 body: apiBody({ action: 'fetch_job_logs', job_id: buildJob.id }) 
4715 |             });
4716 |             const dataLogs = await resLogs.json();
4717 |             const logs = dataLogs.logs || "";
4718 | 
4719 |             // 3. Extract the URL using Regex (looking for the specific pattern in your logs)
4720 |             // Pattern: Artifact download URL: https://github.com/...
4721 |             const urlMatch = logs.match(/Artifact download URL:\s*(https?:\/\/[^\s]+)/);
4722 | 
