5249 |     // --- GENERIC UI ---
5250 |     function formatBytes(bytes) {
5251 |         if (!bytes) return '0 B';
5252 |         const k = 1024;
5253 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5254 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5255 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5256 |     }
