5258 |     function timeAgo(dateString) {
5259 |         const date = new Date(dateString);
5260 |         const now = new Date();
5261 |         const seconds = Math.floor((now - date) / 1000);
5262 |         if (seconds < 10) return 'just now';
5263 |         if (seconds < 60) return seconds + 's ago';
5264 |         const minutes = Math.floor(seconds / 60);
5265 |         if (minutes < 60) return minutes + 'm ago';
5266 |         const hours = Math.floor(minutes / 60);
5267 |         if (hours < 24) return hours + 'h ago';
5268 |         return date.toLocaleDateString();
5269 |     }
