5485 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5486 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5487 |         
5488 |         const navItems = document.querySelectorAll('.nav-item');
5489 |         switchTab(tabId, navItems[navIndex]);
5490 | 
5491 |         const scrollContainer = document.querySelector('.main-view');
5492 |         let retryCount = 0;
5493 |         const MAX_RETRIES = 5;
5494 | 
5495 |         const attemptNavigation = async () => {
5496 |             const element = document.querySelector(selector);
5497 |             
5498 |             if (element) {
5499 |                 console.log("[DeepJump] Element found. Scrolling...");
5500 |                 
5501 |                 // Wait for any tab transition animations
5502 |                 await new Promise(r => setTimeout(r, 300));
5503 | 
5504 |                 let offsetTop = 0;
5505 |                 let curr = element;
5506 |                 while (curr && curr !== scrollContainer) {
5507 |                     offsetTop += curr.offsetTop;
5508 |                     curr = curr.offsetParent;
5509 |                 }
5510 | 
5511 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5512 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5513 | 
5514 |                 // Visual Highlight
5515 |                 element.style.transition = 'all 0.5s ease';
5516 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5517 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5518 |                 setTimeout(() => {
