5520 |                     element.style.boxShadow = '';
5521 |                 }, 3000);
5522 |                 
5523 |                 console.groupEnd();
5524 |                 return true;
5525 |             }
5526 | 
5527 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5528 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5529 |                 retryCount++;
5530 |                 showGlobalToast("🔍 Searching deeper...");
5531 |                 
5532 |                 await loadMoreFn(); 
5533 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5534 |                 return attemptNavigation();
5535 |             }
5536 | 
5537 |             console.error("[DeepJump] Failed: Element not found after retries.");
5538 |             showGlobalToast("Entry not found in recent history.", true);
5539 |             console.groupEnd();
5540 |             return false;
5541 |         };
