8168 |     function extractTableNames(sql) {
8169 |         if (!sql) return [];
8170 |         const tables = [];
8171 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8172 |         
8173 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8174 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8175 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8176 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8177 | 
8178 |         let match;
8179 |         while ((match = fromRegex.exec(sql)) !== null) {
8180 |             const name = match[1];
8181 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8182 |                 tables.push(name);
8183 |             }
8184 |         }
8185 |         
8186 |         while ((match = metaRegex.exec(sql)) !== null) {
8187 |             const name = match[1];
8188 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8189 |                 tables.push(name);
8190 |             }
8191 |         }
8192 | 
8193 |         return tables;
8194 |     }
8195 | 
8196 |     function convertToCSV(resultObj) {
8197 |         const data = resultObj.data || [];
8198 |         if (!data.length) return '';
8199 |         
8200 |         const tables = extractTableNames(resultObj.sql);
8201 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8202 | 
8203 |         const headers = Object.keys(data[0]);
8204 |         const rows = data.map(row => 
8205 |             headers.map(header => {
8206 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8207 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8208 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8209 |             }).join(',')
8210 |         );
8211 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8212 |     }
